"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { useState } from "react";
import {
  Search, MapPin, DoorOpen, Building, Layers, Home,
  Trees, Landmark, Castle, BedDouble, ChevronRight,
} from "lucide-react";
import PropertyCard from "@/components/properties/PropertyCard";
import { MOCK_PROPERTIES } from "@/lib/mock-data";
import { COMMUNES } from "@/lib/constants";

const RECENT = MOCK_PROPERTIES.filter((p) => p.status === "active").slice(0, 8);

const CATEGORIES = [
  { label: "Chanbrèt",  icon: DoorOpen,   href: "/listings?property_type=chambrette", color: "bg-violet-50 text-violet-700" },
  { label: "Studio",    icon: Building,   href: "/listings?property_type=studio",      color: "bg-blue-50 text-blue-700"    },
  { label: "Apatman",   icon: Layers,     href: "/listings?property_type=appartement", color: "bg-sky-50 text-sky-700"      },
  { label: "2 Chanm",   icon: BedDouble,  href: "/listings?property_type=kay_2_chanm", color: "bg-teal-50 text-teal-700"   },
  { label: "3 Chanm+",  icon: Home,       href: "/listings?property_type=kay_3_chanm", color: "bg-caribbean-50 text-caribbean-700" },
  { label: "Villa",     icon: Castle,     href: "/listings?property_type=villa",        color: "bg-amber-50 text-amber-700"  },
  { label: "Terin",     icon: Landmark,   href: "/listings?property_type=te",           color: "bg-green-50 text-green-700"  },
  { label: "Tout Tip",  icon: Trees,      href: "/listings",                            color: "bg-slate-100 text-slate-700" },
];

const COMMUNES_FEATURED = [
  { name: "Okay",       count: "420+", image: "https://images.unsplash.com/photo-1518684079-3c830dcef090?w=400&q=80" },
  { name: "Jakmèl",     count: "280+", image: "https://images.unsplash.com/photo-1506905925346-21bda4d32df4?w=400&q=80" },
  { name: "Port-Salut", count: "95+",  image: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=400&q=80" },
  { name: "Jeremi",     count: "130+", image: "https://images.unsplash.com/photo-1544551763-46a013bb70d5?w=400&q=80" },
];

export default function HomePage() {
  const router = useRouter();
  const [query, setQuery] = useState("");
  const [commune, setCommune] = useState("");

  function handleSearch(e: React.FormEvent) {
    e.preventDefault();
    const params = new URLSearchParams();
    if (commune) params.set("commune", commune);
    if (query) params.set("q", query);
    router.push(`/listings${params.toString() ? `?${params}` : ""}`);
  }

  return (
    <div className="bg-slate-50 min-h-screen">

      {/* ── Search Banner ── */}
      <div className="bg-caribbean-800 py-6 px-4">
        <form onSubmit={handleSearch} className="max-w-3xl mx-auto">
          <div className="flex flex-col sm:flex-row gap-2">
            <div className="flex flex-1 bg-white rounded-xl overflow-hidden border border-transparent focus-within:border-caribbean-400 focus-within:ring-2 focus-within:ring-caribbean-100 transition-all">
              <Search className="w-4 h-4 text-slate-400 ml-3.5 self-center shrink-0" />
              <input
                type="text"
                value={query}
                onChange={(e) => setQuery(e.target.value)}
                placeholder="Kay, studio, villa, terin..."
                className="flex-1 px-3 py-3 text-sm text-slate-900 placeholder-slate-400 bg-white focus:outline-none"
              />
              <div className="hidden sm:flex items-center border-l border-slate-200">
                <MapPin className="w-4 h-4 text-slate-400 ml-3 shrink-0" />
                <select
                  value={commune}
                  onChange={(e) => setCommune(e.target.value)}
                  className="pl-2 pr-8 py-3 text-sm text-slate-700 bg-white focus:outline-none appearance-none cursor-pointer"
                >
                  <option value="">Tout Komin</option>
                  {COMMUNES.map((c) => (
                    <option key={c} value={c}>{c}</option>
                  ))}
                </select>
              </div>
            </div>
            <button
              type="submit"
              className="flex items-center justify-center gap-2 px-6 py-3 bg-sunset-500 hover:bg-sunset-600 active:scale-95 text-white font-bold text-sm rounded-xl transition-all shadow"
            >
              <Search className="w-4 h-4" />
              Chèche
            </button>
          </div>

          {/* Quick chips */}
          <div className="flex flex-wrap gap-2 mt-3">
            {[
              { label: "Studio Okay",           params: "commune=Okay&property_type=studio" },
              { label: "Bò Lanmè Port-Salut",   params: "commune=Port-Salut" },
              { label: "Jakmèl Lwaye",          params: "commune=Jakmèl&listing_type=rent" },
              { label: "Terin pou Vann",        params: "property_type=te&listing_type=sale" },
            ].map(({ label, params }) => (
              <button
                key={label}
                type="button"
                onClick={() => router.push(`/listings?${params}`)}
                className="px-3 py-1 bg-white/15 hover:bg-white/25 border border-white/30 text-white text-xs font-medium rounded-full transition-all"
              >
                {label}
              </button>
            ))}
          </div>
        </form>
      </div>

      {/* ── Categories Grid ── */}
      <section className="max-w-5xl mx-auto px-4 sm:px-6 py-8">
        <h2 className="text-base font-bold text-slate-800 mb-4">
          Chèche pa Kategori
        </h2>
        <div className="grid grid-cols-4 sm:grid-cols-8 gap-3">
          {CATEGORIES.map(({ label, icon: Icon, href, color }) => (
            <Link
              key={href}
              href={href}
              className="flex flex-col items-center gap-2 p-3 bg-white rounded-xl border border-slate-200 hover:border-caribbean-400 hover:shadow-sm transition-all group"
            >
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center ${color} group-hover:scale-110 transition-transform`}>
                <Icon className="w-5 h-5" />
              </div>
              <span className="text-[11px] font-medium text-slate-700 text-center leading-tight">
                {label}
              </span>
            </Link>
          ))}
        </div>
      </section>

      {/* ── Type tabs ── */}
      <section className="max-w-5xl mx-auto px-4 sm:px-6 -mt-2 mb-6">
        <div className="flex gap-2">
          {[
            { label: "Tout", href: "/listings" },
            { label: "Pou Lwaye", href: "/listings?listing_type=rent" },
            { label: "Pou Vann", href: "/listings?listing_type=sale" },
          ].map(({ label, href }) => (
            <Link
              key={href}
              href={href}
              className="px-4 py-1.5 text-sm font-semibold rounded-full border border-slate-200 bg-white text-slate-700 hover:border-caribbean-500 hover:text-caribbean-700 transition-all"
            >
              {label}
            </Link>
          ))}
        </div>
      </section>

      {/* ── Recent Listings ── */}
      <section className="max-w-5xl mx-auto px-4 sm:px-6 pb-8">
        <div className="flex items-center justify-between mb-4">
          <h2 className="text-base font-bold text-slate-800">Dènye Anons</h2>
          <Link
            href="/listings"
            className="flex items-center gap-1 text-xs font-semibold text-caribbean-700 hover:text-caribbean-900 transition-colors"
          >
            Wè tout
            <ChevronRight className="w-3.5 h-3.5" />
          </Link>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {RECENT.map((property) => (
            <PropertyCard key={property.id} property={property} />
          ))}
        </div>
      </section>

      {/* ── Communes ── */}
      <section className="max-w-5xl mx-auto px-4 sm:px-6 pb-10">
        <h2 className="text-base font-bold text-slate-800 mb-4">
          Eksplore pa Komin
        </h2>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          {COMMUNES_FEATURED.map(({ name, count, image }) => (
            <Link
              key={name}
              href={`/listings?commune=${encodeURIComponent(name)}`}
              className="relative overflow-hidden rounded-xl aspect-[4/3] group"
            >
              {/* eslint-disable-next-line @next/next/no-img-element */}
              <img
                src={image}
                alt={name}
                className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
              />
              <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
              <div className="absolute bottom-0 left-0 p-3">
                <p className="font-bold text-white text-sm leading-tight">{name}</p>
                <p className="text-white/80 text-xs">{count} anons</p>
              </div>
            </Link>
          ))}
        </div>
      </section>

    </div>
  );
}
